declare(strict_types=1);use PHPUnit\Framework\TestCase;final class Stage5FMerchantIntelligenceTest extends TestCase{public function testSchemaDefinesSavedReportsAndSchedules():void{$sql=file_get_contents(dirname(__DIR__,2).'/database/stage_5f_merchant_intelligence_reporting.sql');self::assertIsString($sql);self::assertStringContainsString('merchant_saved_reports',$sql);self::assertStringContainsString('merchant_report_schedules',$sql);self::assertStringContainsString('recipient_email_hash',$sql);}public function testDashboardIsMerchantScoped():void{$source=file_get_contents(dirname(__DIR__,2).'/api/merchant/intelligence-dashboard.php');self::assertIsString($source);self::assertStringContainsString("mg_require_permission('merchant.intelligence.view')",$source);self::assertStringContainsString('merchant_user_id=?',$source);foreach(['demand_fact_daily','distribution_programs','merchant_locations','pppm_items','demand_forecast_runs'] as $table)self::assertStringContainsString($table,$source);}public function testReportingRequiresPermissionAndCsrf():void{$source=file_get_contents(dirname(__DIR__,2).'/api/merchant/reports.php');self::assertIsString($source);self::assertStringContainsString('merchant.reports.manage',$source);self::assertStringContainsString('mg_require_csrf_for_write',$source);self::assertStringContainsString("hash_hmac('sha256'",$source);}public function testStage5FReusesExistingForecastAndExportLifecycle():void{$js=file_get_contents(dirname(__DIR__,2).'/assets/js/merchant-intelligence.js');self::assertIsString($js);self::assertStringContainsString('/api/intelligence/forecast.php',$js);self::assertStringContainsString('/api/intelligence/exports.php',$js);self::assertStringContainsString('/api/merchant/reports.php',$js);}public function testMerchantIntelligencePageUsesSharedShell():void{$page=file_get_contents(dirname(__DIR__,2).'/merchant-intelligence.php');self::assertIsString($page);self::assertStringContainsString('includes/merchant-workspace.php',$page);self::assertStringContainsString('merchant-intelligence.css',$page);}}
